let xalarms = global.get("xalarms") || {};

const values = (obj) => Object.values(obj)
const keys = (obj) => Object.keys(obj)
const entries = (obj) => Object.entries(obj)
const getSetup = (xweb) => xweb.setup_data
const getSysinfo = (xweb) => xweb.sysinfo_data
const decode = (text) => decodeURIComponent(text)

for(let [mac,xweb_data] of entries(data)){
    for(let dev of (xweb_data?.devices)){
        xalarms[mac]&&xalarms[mac].devices[dev.uid]&&xalarms[mac].devices[dev.uid].alarms
        &&
        (dev.alarm = entries(xalarms[mac].devices[dev.uid].alarms||{})
        .filter(([,a])=>a.en)
        .map(([pointId,a])=>{
            return {
                pointId,
                name:decode(a.name),
                value:a.value,
                unit:a.unit
            }
        }));
    }
}
return msg;

const payload = msg.payload;
