// @ts-nocheck
let date_now = new Date().getTime();
let limitTime = 900000;

const isMoreThan15Minutes = (start) => (date_now - start) > limitTime;

const decodeText = (str) => {
    const cleaned = str.replace(/%(?![0-9A-Fa-f]{2})/g, '%25');
    return decodeURIComponent(cleaned);
}

const setup_stream = (conf) => {
    let stream = global.get("xstream") || {};
    let getsetup = global.get("xgetsetup") || {};
    let sysInfo = global.get("xsysinfo") || {};

    let communications = global.get("CheckCommunications") || {};
    let mac = conf.mac_address;

    let cate = {}, devices = {}, status_acq = {}, obj_info = {}, commu = {};
    devices[mac] = [], cate[mac] = {}, status_acq[mac] = {}, obj_info[mac] = {}, commu[mac] = {};

    if (getsetup[mac] || stream[mac] || sysInfo[mac]) {
        /*Has key setup_data*/
        if ("setup_data" in (getsetup[mac] || {})) {
            for (let i in getsetup[mac]?.setup_data.setup.ctgs) {
                for (let j in getsetup[mac].setup_data.setup.ctgs[i].devs) {
                    let cate_encoded = encodeURIComponent(getsetup[mac].setup_data.setup.ctgs[i].term)
                    cate[mac][getsetup[mac].setup_data.setup.ctgs[i].devs[j]] = decodeURIComponent(decodeText(cate_encoded));
                }
            }
        }
        status_acq[mac].xwebpro_on = stream[mac].stream_data ? stream[mac].stream_data?.stream?.acq : 0;
        if ("sysinfo_data" in (sysInfo[mac] || {})) {
            let name_encoded = encodeURIComponent(sysInfo[mac].sysinfo_data.info.name);
            obj_info[mac]["name"] = decodeURIComponent(decodeURIComponent(name_encoded));
        }

        /* Has key stream_data */
        if ("stream_data" in (stream[mac] || {})) {
            if ("ts" in stream[mac].stream_data) {
                let offline_time = Number(stream[mac].stream_data.ts);
                /* check offline every 15 min. */
                let overTime = isMoreThan15Minutes(offline_time);

                if (overTime) {
                    if (!communications[mac]) {
                        communications[mac] = {
                            store_name: conf.xweb_name,
                            mac_address: mac,
                            device_name: conf.xweb_name,
                            device_adr: "-",
                            alarm_name: "Offline",
                            text: "Offline",
                            status: true,
                            acknow: false,
                            dateStart: date_now,
                            offline_count: 0,
                            offline_timestamp: null,
                        }
                    } else {
                        if (!communications[mac].status) {
                            communications[mac] = {
                                ...communications[mac],
                                status: true,
                                acknow: false,
                                dateStart: date_now,
                                offline_count: 0,
                                offline_timestamp: null,
                            }
                        }
                    }
                } else {
                    if (communications[mac]) {
                        communications[mac] = {
                            ...communications[mac],
                            status: false,
                        }
                    }
                }
            }

            if ("stream" in (stream[mac].stream_data || {})) {
                for (let i in stream[mac].stream_data.stream.data) {
                    let deviceId = i;
                    let adr = getsetup[mac].setup_data?.devices[deviceId]?.gen.addr2;
                    let name = decodeURIComponent(getsetup[mac].setup_data?.devices[deviceId]?.gen.name);
                    cate[mac] = cate[mac][deviceId] || "Others";

                    let object = {};
                    object[mac] = {
                        analogInput: [],
                        deviceStatus: [],
                        alarm: [],
                        digitalinput: [],
                        outputStatus: [],

                        chartDef: [],
                    }

                    let model = getsetup[mac].setup_data?.devices[deviceId]?.gen.model;
                    let dbpath = getsetup[mac].setup_data?.devices[deviceId]?.gen.dbpath;

                    for (let j in getsetup[mac].setup_data?.devices[deviceId]?.vrs) {
                        if (getsetup[mac].setup_data?.devices[deviceId]?.vrs[j].vfr == 1) {
                            let pointId = j;
                            let group;
                            let point_name;

                            if (getsetup[mac].setup_data?.devices[deviceId]?.vrs[pointId]) {
                                let vgrp = getsetup[mac].setup_data?.devices[deviceId]?.vrs[pointId].vgrp;

                                switch (vgrp) {
                                    case 0:
                                        group = "analogInput";
                                        break;
                                    case 1:
                                        group = "deviceStatus";
                                        break;
                                    case 2:
                                        group = "alarm";
                                        break;
                                    case 3:
                                        group = "digitalinput";
                                        break;
                                    case 4:
                                        group = "outputStatus";
                                        break;
                                }
                                if (getsetup[mac].setup_data?.devices[deviceId]?.lng.vrs[pointId].uvun) {
                                    let uvun_encoded = encodeURIComponent(getsetup[mac].setup_data?.devices[deviceId]?.lng.vrs[pointId].uvun);
                                    point_name = decodeURIComponent(uvun_encoded);
                                } else {
                                    let vun_encoded = encodeURIComponent(getsetup[mac].setup_data?.devices[deviceId]?.lng.vrs[pointId].vun);
                                    point_name = decodeURIComponent(vun_encoded);
                                }
                                point_name = decodeText(point_name);

                                if (getsetup[mac].setup_data?.devices[deviceId].vrs[pointId].chartDef.en === true) {
                                    object[mac]["chartDef"].push({
                                        pointId: pointId,
                                        name: point_name,
                                        value: stream[mac].stream_data.stream.data[deviceId][pointId] || 0,
                                        index: j,
                                        unit: getsetup[mac].setup_data?.devices[deviceId].vrs[pointId].vudm,
                                    })
                                }
                                if (object[mac][group]) {
                                    object[mac][group].push({
                                        pointId: pointId,
                                        name: point_name,
                                        value: stream[mac].stream_data.stream.data[deviceId][pointId] || 0,
                                        unit: getsetup[mac].setup_data?.devices[deviceId].vrs[pointId].vudm,
                                    })
                                }
                            }
                        }
                    }

                    devices[mac].push({
                        name: name,
                        adr: adr,
                        cate: cate[mac],
                        uid: i,
                        lanid: getsetup[mac].setup_data?.devices[deviceId]?.gen.addr1,
                        model: model,
                        dbpath: dbpath,
                        analogInput: object[mac]["analogInput"],
                        deviceStatus: object[mac]["deviceStatus"],
                        alarm: object[mac]["alarm"],
                        digitalinput: object[mac]['digitalinput'],
                        outputStatus: object[mac]['outputStatus'],

                        chartDef: object[mac]["chartDef"],
                    });
                }
            }
        } else {
            communications[mac] = {
                ...communications[mac],
                status: true,
                acknow: false,
                dateStart: date_now,
                offline_count: 0,
                offline_timestamp: null,
            }
        }

        global.set("CheckCommunications", communications);
        return { devices, status_acq, obj_info };
    }
}
const output = {};
for (let conf of msg.config_url) {
    let compares = setup_stream(conf);
    let mac = conf.mac_address;
    output[mac] = {};
    output[mac].name = compares?.obj_info[mac].name || conf.xweb_name;
    output[mac].mac_address = mac;
    output[mac].on = compares?.status_acq[mac].xwebpro_on || 0;
    output[mac].branch_id = conf.branch_id;
    output[mac].devices = compares?.devices[mac] || [];
}
// flow.set("data", output);
msg.payload = output;
return msg;
